      "sectionStatus": "done",
      "items": {
        "problemDefinition": "现有 tarball 验收只检查构建与 CSS，不证明已安装发布产物在真实浏览器中呈现和切换主题。",
        "requirementsDefinition": "nested isolated 与 workspace-hoisted 两种 tarball 消费者都必须 typecheck、build、验证 CSS，并运行 Playwright 主题/状态/图表/边界矩阵。",
        "nonGoals": [
          "不执行私有 registry 发布",
          "不使用或请求发布凭据"
        ],
        "plainLanguage": "让发布产物在两种真实安装布局中接受和工作区相同的浏览器验收。",
        "candidateOptions": {
          "A": "只检查打包 CSS",
          "B": "打包后启动浏览器矩阵"
        },
        "recommendedOption": {
          "option": "B",
          "rationale": "可验证运行时解析、渲染与主题交互，而非只验证产物文本。"
        },
        "openDecisions": "registry 认证为外部后续项，非当前本地验收阻塞。",
        "granularityDecision": "fine-enough：两个布局共享同一发布态浏览器不变量。",
        "testCaseDesign": "每个布局执行现有 8 project Playwright matrix。",
        "acceptanceToTestMapping": "nested/hoisted→verify:packed-consumer 中 typecheck/build/CSS/browser。",
        "regressionTestDesign": "包解析、@source、主题运行时或截图失效均会失败。",
        "coverageAssessment": "target-driven",
        "residualRisk": "远端私有 registry 认证和发布策略仍需有凭据的发布者验证。",
        "readiness": {
          "readiness": "Yes",
          "reason": "tarball、临时消费者与 Playwright 已在仓库可用。"
        }
      }
    },
